INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (176,15,'\"Do you like tea?\" ??? She asked ___ I liked tea.','that','if','what','whether','D','Yes/no questions: if or whether.',2,'2026-05-15 13:28:09',29,'multiple_choice',NULL);
INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (177,15,'\"Are you coming?\" ??? She asked if I ___.','was coming','am coming','will come','came','A','Present Continuous ??? Past Continuous.',3,'2026-05-15 13:28:09',29,'multiple_choice',NULL);
INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (178,15,'\"What time is it?\" ??? He asked what time ___.','it is','it was','is it','was it','B','Reported question: statement word order.',4,'2026-05-15 13:28:09',29,'multiple_choice',NULL);
INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (179,15,'Which reported question is CORRECT?','She asked where did I work.','She asked where I worked.','She asked where I did work.','She asked where do I work.','B','Reported: statement word order (no auxiliary inversion).',5,'2026-05-15 13:28:09',29,'multiple_choice',NULL);
