INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (181,15,'She ___ me that she was busy.','said','told','spoke','talked','B','tell + person: told me.',1,'2026-05-15 13:28:09',30,'multiple_choice',NULL);
