INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (183,15,'\"I went to Paris.\" ??? She said she ___ to Paris.','went','had gone','has gone','goes','B','Past Simple ??? Past Perfect.',3,'2026-05-15 13:28:09',30,'multiple_choice',NULL);
INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (184,15,'Which sentence is INCORRECT?','She told that she was tired.','She said that she was tired.','She told me that she was tired.','She said she was tired.','A','tell needs an object: told me/him/her.',4,'2026-05-15 13:28:09',30,'multiple_choice',NULL);
