INSERT INTO "grammar_questions" ("id", "lesson_id", "question", "option_a", "option_b", "option_c", "option_d", "correct", "explanation", "order_index", "created_at", "section_id", "question_type", "fill_answer") VALUES (200,16,'She is _____ (tall) girl in her school.',NULL,NULL,NULL,NULL,NULL,'1-syllable: the + adjective + est.',7,'2026-05-15 13:28:09',32,'fill_blank','the tallest');
