INSERT INTO "toeic_tests" ("id", "title", "type", "duration_minutes", "difficulty", "description", "status", "created_by", "created_at") VALUES (1,'TOEIC Reading test 1 ','mini_test',120,'medium','Từ Part 5 - 6 - 7\n','public',1,'2026-05-15 22:30:52');
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (9,1,6,1,NULL,NULL,'Look to Riessler Landscaping for your Garden Needs\r\nRiessler Landscaping has everything you need to create your dream garden. We will listen to your ideas and offer suggestions that match your gardening desires. 131 The nursery here at Riessler Landscaping includes plants of many varieties and sizes that burst with eye-catching colors year-round. You are guaranteed to find something that will add 132 to your garden. We are 133 equipped to construct small ponds or other water features. And as our name suggests, we can take on more ambitious landscaping projects—whatever you need! With more than 40 years in the landscape—design business, 134 expertise is unmatched.',NULL);
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (10,1,6,2,NULL,NULL,'10 JanuaryCindy Mulligan88 Manchester RoadHARROGATEHG82 2MJDear Ms. Mulligan,We are delighted to celebrate your 30th anniversary with Brandrix Distribution Centre. _135 Your dedication, loyalty, and hard work have contributed greatly to our success over the years. We appreciate your commitment to excellence. Over the years, you _136 great initiative, creativity, and leadership.You will 137 be receiving a commemorative plaque by post. We hope this token of our gratitude reminds you how much you mean to us.Congratulations on reaching this 138 Thank you for being part of our Brandrix family.Sincerely,Lance Powar, Vice President of Human ResourcesBrandrix Distribution Centre',NULL);
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (11,1,6,3,NULL,NULL,'To: Kay Berman <kberman@xmail.com>From: Ali Chaleby <achaleby@ralenciadesign.com>Date: August 21Subject: Plans for living roomAttachment: SamplesDear Ms. Berman,My design team is in the process of 139 the plans for your living room. Based on our last conversation, I have chosen different paints for the walls and borders. Please review the attached file and decide whether you like those new 140 If not, it is not too late to make a change. 141 Your review will help us refine the design before we start.Please let 142 know if you have any questions. I look forward to hearing from you.Kind regards,Ali Chaleby, Ralencia Design',NULL);
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (12,1,6,4,NULL,NULL,'To: Marsha Zalen <mzalen@mansfield.com>From: Kaymar PCP <info@kaymarpcp.com>Date: September 8Subject: Your recent office visitDear Ms. Zalen,Thank you for your recent visit to Kaymar Primary Care Practice. We hope you found our services (143) -------, and we welcome suggestions for improvement.We have posted a (144) ------- of your consultation on our portal. Please take a moment to go through it and let us know if you have any questions.As a reminder, you can log in to the portal for various activities. (145) -------, you can make appointments and payments, view your medical history, review lab results, and request medication refills. (146) -------. Rest assured that your personal information is safe and secure.We thank you for your business and look forward to serving you again.Kaymar Primary Care Practice',NULL);
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (13,1,7,1,NULL,NULL,'Questions 147-148 refer to the following notice.\r\n\r\n\r\nDear High View Apartments Resident,\r\n\r\nRiverside Paving Company is coming to High View Apartments on May 3 and 4 to resurface the parking area. All vehicles must be removed by 8 A.M. on May 3 for the work to commence. Residents may use the parking area again starting on May 5 at 8 A.M. We realize that trying to find another place to park is inconvenient, but it is necessary for the job to be completed in the two days scheduled. Note that all parking spaces will be widened, and some spaces could be moved during the work. You will receive an e-mail if your parking space is moved more than 20 meters from your previous one.\r\n\r\nThank you for your cooperation, Judith Alvarez, Property Manager',NULL);
INSERT INTO "toeic_question_groups" ("id", "test_id", "part_num", "group_order", "audio_url", "image_url", "passage", "transcript") VALUES (14,1,7,2,NULL,'http://localhost:5000/uploads/toeic/1779961624364_26_05_23_02_02_13.png',NULL,NULL);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (303,1,NULL,5,101,'The lecture will take place at 6:00 P.m., ------- which attendees may ask questions.',NULL,NULL,'across','after','inside','among','B','Chọn giới từ \"after\" (sau khi). \"After which\" đóng vai trò nối mệnh đề: bài giảng diễn ra lúc 6h tối, sau đó người tham gia có thể đặt câu hỏi.',1);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (304,1,NULL,5,102,'The ------- antique shop in Pepper Valley will close down next month.',NULL,NULL,'last','lasts','lasted','lasting','A','Cần một tính từ/từ xác định để bổ nghĩa cho cụm danh từ \"antique shop\". \"The last antique shop\" nghĩa là cửa hàng đồ cổ cuối cùng.',2);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (305,1,NULL,5,103,'Merryville residents will receive an online status -----— about the ongoing bridge construction project.',NULL,NULL,'update','change','payment','request','A','Dựa vào ngữ cảnh, người dân sẽ nhận được một sự \"status update\" (cập nhật trạng thái) trực tuyến về dự án xây dựng cầu.',3);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (306,1,NULL,5,104,'As a result of ------- many years leading media organizations, Ms. Ayo was selected for the Dowel Journalism Prize.',NULL,NULL,'she','her','hers','herself','B','Cần tính từ sở hữu \"her\" để đứng trước cụm danh từ/V-ing \"many years leading...\".',4);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (307,1,NULL,5,105,'To stop the ------- of computer viruses, do not open suspicious e-mails.',NULL,NULL,'break','spread','balance','surface','B','Cần danh từ phù hợp ngữ nghĩa: \"stop the spread of computer viruses\" (ngăn chặn sự lây lan của virus máy tính).',5);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (308,1,NULL,5,106,'The hiring manager ------- considered each applicant''s résumé and qualifications.',NULL,NULL,'caring','careful','carefully','carefulness','C','Cần một trạng từ (adv) \"carefully\" để bổ nghĩa cho động từ \"considered\".',6);
