INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (377,1,12,6,143,'We hope you found our services (143) -------',NULL,NULL,'satisfied','satisfaction','satisfactory','satisfactorily','C','Áp dụng cấu trúc: \"find something + adj\" (nhận thấy cái gì đó như thế nào). Dùng tính từ \"satisfactory\" (vừa ý, thỏa đáng) để mô tả tính chất cho \"our services\".',1);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (378,1,12,6,144,'We have posted a (144) ------- of your consultation on our portal.',NULL,NULL,'photo','lecture','summary','schedule','C','Sau khi đi khám bệnh/tư vấn, phòng khám thường đăng tải một bản \"summary\" (tóm tắt) nội dung cuộc kiểm tra lên hệ thống cổng thông tin portal để bệnh nhân dễ dàng xem lại.',2);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (379,1,12,6,145,'(145) -------, you can make appointments and payments...',NULL,NULL,'To repeat','For instance','Otherwise','Consequently','B','Phía sau đưa ra một loạt hành động cụ thể (đặt lịch, thanh toán, xem bệnh án...), đây là các ví dụ minh họa cho cụm \"various activities\" ở câu trước. Chọn \"For instance\" (Ví dụ như).',3);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (380,1,12,6,146,'request medication refills. (146) -------. Rest assured that your personal information is safe and secure.',NULL,NULL,'We hope you will use this resource to manage your health-care needs.','The staff will close the office early on Friday afternoons.','Please be sure to come to our office fifteen minutes in advance.','We apologize for any confusion about your appointment time.','A','Chọn câu A (Chúng tôi hy vọng bạn sẽ sử dụng nguồn tài nguyên này để quản lý các nhu cầu chăm sóc sức khỏe của mình) để đúc kết lại lợi ích của cổng thông tin portal vừa được liệt kê bên trên.',4);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (381,1,13,7,147,'What is the purpose of the notice?',NULL,NULL,'To invite residents to a meeting on May 3','To request feedback about parking facilities','To inform residents of an upcoming project','To announce an increase in parking fees','C','Thông báo nói về việc công ty Riverside Paving Company sẽ đến trải lại bề mặt khu vực đỗ xe (resurface the parking area), đây là một dự án sắp diễn ra nên chọn C.',1);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (382,1,13,7,148,'What is suggested about High View Apartments?',NULL,NULL,'It charges residents a monthly maintenance fee.','It recently hired a new property manager.','It has the parking area repaved every year.','It assigns tenants specific parking spots.','D','Bài đọc có câu: \"You will receive an e-mail if your parking space is moved more than 20 meters from your previous one\" (Bạn sẽ nhận email nếu chỗ đậu xe của bạn bị dịch chuyển...), chứng tỏ chung cư này có chỉ định vị trí đỗ xe cụ thể cho từng cư dân.',2);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (383,1,14,7,149,'What most likely is Ms. Seang''s job?',NULL,NULL,'Glassmaker','Art instructor','Beach lifeguard','Program administrator','B','Dựa vào nội dung đoạn hội thoại trong ảnh, Carol nhắc tới \"buổi hội thảo mosaic (ghép tranh) của cô vào ngày mai\", do đó cô Seang khả năng cao nhất là một giáo viên dạy nghệ thuật (Art instructor).',4);
INSERT INTO "toeic_questions" ("id", "test_id", "group_id", "part_num", "question_num", "question_text", "image_url", "audio_url", "option_a", "option_b", "option_c", "option_d", "correct_answer", "explanation", "order_index") VALUES (384,1,14,7,150,'At 11:23 A.M., what does Ms. Seang imply when she writes, \"I have plenty to go around\"?',NULL,NULL,'She intends to create an extra-large mosaic.','She has been collecting sea glass for many years.','She can share her sea glass with all the workshop participants.','She does not think she will use much of her sea glass.','C','Cụm từ \"plenty to go around\" trong ảnh nghĩa là có đủ cho tất cả mọi người, ám chỉ cô có thể chia sẻ số thủy tinh biển này cho toàn bộ học viên tham gia buổi hội thảo.',2);
